    13→type slackConfig struct {
    14→	WebhookURL string `json:"webhook_url"`
    15→}
    16→
    17→// SlackSender sends notifications as Slack Block Kit messages via incoming webhook.
    18→type SlackSender struct {
    19→	Client *http.Client
    20→}
    21→
    22→// slackPayload is the Slack incoming webhook payload using Block Kit.
    23→type slackPayload struct {
    24→	Blocks []slackBlock `json:"blocks"`
    25→}
    26→
    27→type slackBlock struct {
    28→	Type string     `json:"type"`
    29→	Text *slackText `json:"text,omitempty"`
    30→}
    31→
    32→type slackText struct {
    33→	Type string `json:"type"`
    34→	Text string `json:"text"`
    35→}
    36→
    37→func (s *SlackSender) Send(ctx context.Context, ch *models.NotificationChannel, msg Notification) error {
    38→	var cfg slackConfig
    39→	if err := json.Unmarshal(ch.Config, &cfg); err != nil {
    40→		return fmt.Errorf("parse slack config: %w", err)
    41→	}
    42→
    43→	payload := slackPayload{
    44→		Blocks: []slackBlock{
    45→			{
    46→				Type: "header",
    47→				Text: &slackText{Type: "plain_text", Text: msg.Title},
    48→			},
    49→			{
    50→				Type: "section",
    51→				Text: &slackText{Type: "mrkdwn", Text: msg.Body},
    52→			},
    53→		},
    54→	}
    55→
    56→	body, err := json.Marshal(payload)
    57→	if err != nil {
    58→		return fmt.Errorf("marshal slack payload: %w", err)
    59→	}
    60→
    61→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, cfg.WebhookURL, bytes.NewReader(body))
    62→	if err != nil {
    63→		return fmt.Errorf("create request: %w", err)
    64→	}
    65→	req.Header.Set("Content-Type", "application/json")
    66→
    67→	client := s.Client
    68→	if client == nil {
    69→		client = http.DefaultClient
    70→	}
    71→
    72→	resp, err := client.Do(req)
    73→	if err != nil {
    74→		return fmt.Errorf("send slack notification: %w", err)
    75→	}
    76→	defer resp.Body.Close()
    77→
    78→	if resp.StatusCode >= 400 {
    79→		return fmt.Errorf("slack returned status %d", resp.StatusCode)
    80→	}
    81→	return nil
    82→}
    83→

