    48→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
    49→		return
    50→	}
    51→	ch.Type = strings.TrimSpace(ch.Type)
    52→	ch.Name = strings.TrimSpace(ch.Name)
    53→	if ch.Type == "" {
