    62→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "config is required")
    63→		return
    64→	}
    65→	if err := h.store.CreateChannel(r.Context(), &ch); err != nil {
    66→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to create channel")
    67→		return
    68→	}
    69→	RespondJSON(w, r, http.StatusCreated, ch)
    70→}
